sql:
SELECT AVG(property_value) AS average_atomic_radius
FROM material_properties
WHERE property_name = 'atomic radius';

SELECT DISTINCT m.name
FROM materials m
INNER JOIN access_logs al ON m.material_id = al.material_id;

SELECT COUNT(*) AS material_count
FROM compositions
WHERE element = 'Ti';

external_knowledge:
- 'visited more than once' refers to having more than one entry in the access logs within the specified date range; 
- 'metallic radius' is a property of materials and can be used to understand their atomic structure; 
- 'May 2023' is the time frame for the access logs.

sql:
SELECT AVG(percentage) AS average_percentage
FROM compositions
WHERE element = 'Ni';

SELECT material_id, MAX(version_date) AS latest_version_date
FROM material_versions
GROUP BY material_id;

SELECT name
FROM materials
WHERE metallic_radius = (SELECT MAX(metallic_radius) FROM materials);
